return [{
  json: {
    module: {
      key: "attachment",
      label: "Email attachments",
      order: 150,
      enabled: true,
      html: input.html
    }
  }
}];

const input = $input.first().json;

return [{
  json: {
    module: {
      key: "email",
      label: "Email history",
      order: 100,
      enabled: true,
      html: input.html
    }
  }
}];

const base = $('Start').first().json;
const items = $input.all();

const includeModules = base.query?.includeModules || [];

const modules = Array.isArray(base.modules)
  ? [...base.modules]
  : [];

for (const item of items) {
  const module = item.json?.module;
  if (!module?.key) continue;
  if (module.enabled === false) continue;

  if (includeModules.includes(module.key))
  {
    modules.push(module);
  }
}

modules.sort((a, b) => (a.order ?? 9999) - (b.order ?? 9999));

return [
  {
    json: {
      ...base,
      modules,
      modulesHtml: modules
        .map(m => m.html)
        .filter(Boolean)
        .join("\n\n")
    }
  }
];

